      "height": "178cm",
      "weight": "75kg",
      "hair": "Light brown curly hair",
      "face": "Weathered face, red eyes.",
      "features": "None.",
      "clothing": "Tailcoat with left shoulder armor, trousers with left knee armor, black leather shoes.",
      "weapon": "轻语, Four-shot revolver, can be converted to sniper rifle with barrel, stock, and scope."
    }
  },
  "char_background": {
    "origin": "Military veteran whose battlefield trauma after discharge spiraled into mental breakdown, triggering 灵力 awakening, frames killing as art: each murder a carefully composed piece. The ambush that blinded 慎 was his orchestration.",
    "current_mission": "Continues killing his way, each scene deliberately arranged."
  },
  "char_special_abilities": {
    "灵力回路-绽放": "Constructs bullets from 灵力. Upon impact, they bloom like flowers from within the target, causing internal pain beyond the physical wound."
  },
  "char_relationships": {
    "炼司": "The only gunsmith he trusts, built 轻语 for him. The only name scratched out in the ledger.",
    "慎": "The 狩灵 he blinded in an orchestrated ambush, a work he considers incomplete: the man still moves, still hunts, still refuses to break.",
    "劫": "Ambushed in the same incident, watches her hunt him across prefectures with detached curiosity, her escalating desperation holding his attention."
  }
}
